1	type Item = {
2	  type: string;
3	  material?: string;
4	  cursed?: boolean;
5	  enchantment?: number;
6	};
7	
8	type Customer = { yearsWithMHPCO: number };
9	
10	type QuoteStep = { op: "quote"; items: Item[] };
11	
12	type Damage = { itemType: string; amount: number };
13	
14	type ClaimStep = {
15	  op: "claim";
16	  policy: number;
17	  incident: { cause: string; damages: Damage[] };
18	};
19	
20	type Step = QuoteStep | ClaimStep;
21	
22	type Scenario = {
23	  customer: Customer;
24	  steps: Step[];
25	};
26	
27	type ScenarioResult = {
28	  results: { premium?: number; payout?: number; remainingCap?: number }[];
29	};
30	
31	const PROCESSING_FEE = 5;
32	
33	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
34	
35	const firstInsuranceSurcharge = (premium: number): number =>
36	  premium * FIRST_INSURANCE_SURCHARGE_RATE;
37	
38	const COMPONENT_PREMIUM = 25;
39	
40	const BASE_PREMIUMS: Record<string, number> = {
41	  sword: 100,
42	  amulet: 60,
43	  staff: 80,
44	  potion: 40,
45	  rune: COMPONENT_PREMIUM,
46	  moonstone: COMPONENT_PREMIUM,
47	};
48	
49	const BLOCK_PREMIUM = 60;
50	
51	const isBlock = (count: number): boolean => count === 3;
52	
53	const countBy = <T>(
54	  values: T[],
55	  keyOf: (value: T) => string,
56	): Record<string, number> =>
57	  values.reduce<Record<string, number>>((counts, value) => {
58	    counts[keyOf(value)] = (counts[keyOf(value)] ?? 0) + 1;
59	    return counts;
60	  }, {});
61	
62	const countByType = (items: Item[]): Record<string, number> =>
63	  countBy(items, (item) => item.type);
64	
65	const premiumForGroup = (type: string, count: number): number =>
66	  isBlock(count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
67	
68	const basePremiumFor = (items: Item[]): number =>
69	  Object.entries(countByType(items)).reduce(
70	    (total, [type, count]) => total + premiumForGroup(type, count),
71	    0,
72	  );
73	
74	const roundUpToWholeGold = (amount: number): number => Math.ceil(amount);
75	
76	const roundDownToWholeGold = (amount: number): number => Math.floor(amount);
77	
78	const sumBy = (items: Item[], valueOf: (item: Item) => number): number =>
79	  items.reduce((total, item) => total + valueOf(item), 0);
80	
81	const surchargeFor = (
82	  items: Item[],
83	  qualifies: (item: Item) => boolean,
84	  rate: number,
85	): number =>
86	  sumBy(items, (item) =>
87	    qualifies(item) ? BASE_PREMIUMS[item.type] * rate : 0,
88	  );
89	
90	const CURSE_SURCHARGE_RATE = 0.5;
91	
92	const isCursed = (item: Item): boolean => item.cursed === true;
93	
94	const curseSurchargeFor = (items: Item[]): number =>
95	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
96	
97	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
98	
99	const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
100	
101	const isHighlyEnchanted = (item: Item): boolean =>
102	  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD;
103	
104	const enchantmentSurchargeFor = (items: Item[]): number =>
105	  surchargeFor(items, isHighlyEnchanted, ENCHANTMENT_SURCHARGE_RATE);
106	
107	const discountFor = (
108	  qualifies: boolean,
109	  premium: number,
110	  rate: number,
111	): number => (qualifies ? premium * rate : 0);
112	
113	const LOYALTY_DISCOUNT_RATE = 0.2;
114	
115	const LOYALTY_YEARS_THRESHOLD = 2;
116	
117	const loyaltyDiscountFor = (customer: Customer, premium: number): number =>
118	  discountFor(
119	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
120	    premium,
121	    LOYALTY_DISCOUNT_RATE,
122	  );
123	
124	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
125	
126	const followUpDiscountFor = (isFollowUp: boolean, premium: number): number =>
127	  discountFor(isFollowUp, premium, FOLLOW_UP_DISCOUNT_RATE);
128	
129	const isKnownItemType = (item: Item): boolean => item.type in BASE_PREMIUMS;
130	
131	const assertKnownItemTypes = (items: Item[]): void => {
132	  for (const item of items) {
133	    if (!isKnownItemType(item)) {
134	      throw new Error(`Unknown item type: ${item.type}`);
135	    }
136	  }
137	};
138	
139	const quotePremium = (
140	  customer: Customer,
141	  items: Item[],
142	  isFollowUp: boolean,
143	): number => {
144	  assertKnownItemTypes(items);
145	  const basePremium = basePremiumFor(items);
146	  return roundUpToWholeGold(
147	    basePremium +
148	      curseSurchargeFor(items) +
149	      enchantmentSurchargeFor(items) +
150	      firstInsuranceSurcharge(basePremium) -
151	      loyaltyDiscountFor(customer, basePremium) -
152	      followUpDiscountFor(isFollowUp, basePremium) +
153	      PROCESSING_FEE,
154	  );
155	};
156	
157	const DEDUCTIBLE = 100;
158	
159	const HIGH_ENCHANTMENT_THRESHOLD = 8;
160	
161	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
162	
163	const reimbursementRateFor = (item: Item | undefined): number =>
164	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
165	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
166	    : 1;
167	
168	const insuredItemFor = (
169	  insuredItems: Item[],
170	  damage: Damage,
171	): Item | undefined =>
172	  insuredItems.find((item) => item.type === damage.itemType);
173	
174	const payoutForDamage = (insuredItems: Item[], damage: Damage): number =>
175	  damage.amount * reimbursementRateFor(insuredItemFor(insuredItems, damage)) -
176	  DEDUCTIBLE;
177	
178	const insuredItemsForPolicy = (steps: Step[], policy: number): Item[] => {
179	  const policyStep = steps[policy];
180	  return policyStep.op === "quote" ? policyStep.items : [];
181	};
182	
183	const assertDamagesCoveredByPolicy = (
184	  insuredItems: Item[],
185	  damages: Damage[],
186	): void => {
187	  const insuredCounts = countByType(insuredItems);
188	  const damageCounts = countBy(damages, (damage) => damage.itemType);
189	  for (const [itemType, damageCount] of Object.entries(damageCounts)) {
190	    if (damageCount > (insuredCounts[itemType] ?? 0)) {
191	      throw new Error(`Item type not in policy: ${itemType}`);
192	    }
193	  }
194	};
195	
196	const claimPayout = (insuredItems: Item[], damages: Damage[]): number =>
197	  damages.reduce(
198	    (total, damage) => total + payoutForDamage(insuredItems, damage),
199	    0,
200	  );
201	
202	const INSURANCE_VALUES: Record<string, number> = {
203	  sword: 1000,
204	  amulet: 600,
205	  rune: 250,
206	};
207	
208	const CAP_MULTIPLIER = 2;
209	
210	const insuranceSumFor = (items: Item[]): number =>
211	  sumBy(items, (item) => INSURANCE_VALUES[item.type]);
212	
213	const remainingCapFor = (insuredItems: Item[], totalPaid: number): number =>
214	  CAP_MULTIPLIER * insuranceSumFor(insuredItems) - totalPaid;
215	
216	const claimResult = (
217	  steps: Step[],
218	  step: ClaimStep,
219	  alreadyPaid: number,
220	): { payout: number; remainingCap: number } => {
221	  const insuredItems = insuredItemsForPolicy(steps, step.policy);
222	  assertDamagesCoveredByPolicy(insuredItems, step.incident.damages);
223	  const capBeforePayout = remainingCapFor(insuredItems, alreadyPaid);
224	  const payout = roundDownToWholeGold(
225	    Math.min(claimPayout(insuredItems, step.incident.damages), capBeforePayout),
226	  );
227	  return { payout, remainingCap: capBeforePayout - payout };
228	};
229	
230	export const runScenario = (scenario: Scenario): ScenarioResult => {
231	  const paidByPolicy: Record<number, number> = {};
232	  return {
233	    results: scenario.steps.map((step, index) => {
234	      if (step.op === "quote") {
235	        return {
236	          premium: quotePremium(scenario.customer, step.items, index > 0),
237	        };
238	      }
239	      const alreadyPaid = paidByPolicy[step.policy] ?? 0;
240	      const result = claimResult(scenario.steps, step, alreadyPaid);
241	      paidByPolicy[step.policy] = alreadyPaid + result.payout;
242	      return result;
243	    }),
244	  };
245	};
